void backtrack(int* nums, int numsSize, int* current, int currentSize, int* used, int** result, int* returnSize, int** returnColumnSizes) {
    if (currentSize == numsSize) {
        result[*returnSize] = (int*)malloc(numsSize * sizeof(int));
        memcpy(result[*returnSize], current, numsSize * sizeof(int));
        returnColumnSizes[0][*returnSize] = numsSize;
        (*returnSize)++;
        return;
    }

    for (int i = 0; i < numsSize; i++) {
        if (used[i]) continue;
        current[currentSize] = nums[i];
        used[i] = 1;
        backtrack(nums, numsSize, current, currentSize + 1, used, result, returnSize, returnColumnSizes);
        used[i] = 0;
    }
}

int** permute(int* nums, int numsSize, int* returnSize, int** returnColumnSizes) {
    int maxPerms = 1;
    for (int i = 1; i <= numsSize; i++) maxPerms *= i;

    int** result = (int**)malloc(maxPerms * sizeof(int*));
    *returnColumnSizes = (int*)malloc(maxPerms * sizeof(int));
    *returnSize = 0;

    int* current = (int*)malloc(numsSize * sizeof(int));
    int* used = (int*)calloc(numsSize, sizeof(int));

    backtrack(nums, numsSize, current, 0, used, result, returnSize, returnColumnSizes);

    free(current);
    free(used);
    return result;
}

